import { getMockApiUrls } from "./get-mock-api-urls";
import { expect, test } from "./test-fixture";

const urls = getMockApiUrls();

const mockUser = {
  id: 1,
  email: "test@example.com",
  cognito_sub: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

const mockOrgTenant = {
  id: 42,
  tenant_type: "org" as const,
  name: "Hope Foundation",
  org_id: "org-42",
  vendor_id: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

test("sidebar shows empty state when the user has no tenants", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, { body: [] });

  // Users without a tenant are redirected to /organizations/new, which still
  // renders the AppSidebar inside the _authed layout.
  await page.goto("/organizations/new", { waitUntil: "networkidle" });

  await expect(page.getByText("No tenants yet")).toBeVisible();
  await expect(
    page.getByRole("button", { name: /Switch organization/i }),
  ).toHaveCount(0);
});

test("sidebar shows the current tenant and its initials when the user has a tenant", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, { body: [mockOrgTenant] });
  await mockServerRequest.GET(urls.campaignsIndex(42), { body: [] });

  await page.goto("/", { waitUntil: "networkidle" });

  await expect(page.getByText("No tenants yet")).toHaveCount(0);

  const switcher = page.getByRole("button", { name: "Switch organization" });
  await expect(switcher).toBeVisible();
  await expect(switcher).toContainText("Hope Foundation");
  await expect(switcher).toContainText("HF");
});

test("sidebar lists all tenants in the switcher dropdown", async ({
  page,
  mockServerRequest,
}) => {
  const secondTenant = {
    id: 43,
    tenant_type: "vendor" as const,
    name: "Acme Vendor",
    org_id: null,
    vendor_id: "ven-43",
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, {
    body: [mockOrgTenant, secondTenant],
  });
  await mockServerRequest.GET(urls.campaignsIndex(42), { body: [] });

  await page.goto("/", { waitUntil: "networkidle" });

  await page.getByRole("button", { name: "Switch organization" }).click();

  const menu = page.getByRole("menu");
  await expect(menu).toBeVisible();
  await expect(menu.getByRole("menuitem", { name: /Hope Foundation/ })).toBeVisible();
  await expect(menu.getByRole("menuitem", { name: /Acme Vendor/ })).toBeVisible();
});

